import numpy as np
import tensorflow as tf
from tensorflow.keras import models
from tensorflow.keras.layers import (
    BatchNormalization,
    Conv2D,
    Concatenate,
    Dropout,
    Input,
    LeakyReLU,
    MaxPooling2D,
    Lambda,
    Dense,
    Softmax,
    Multiply,
    Subtract,
)
import tensorflow.keras.backend as K

from psanp.classifiers.tensorflow.susann_v2_classifier.settings import Settings

tf.compat.v1.disable_eager_execution()


def Conv2DPreluBN(
    depth, kernel_size=(1, 1), strides=(1, 1), batch_normalization=False, name=""
):
    def wrapper(input_tensor):
        x = Conv2D(
            depth,
            kernel_size,
            strides=strides,
            padding="same",
            use_bias=False,
            name=name + "_conv2d",
        )(input_tensor)
        if batch_normalization:
            x = BatchNormalization()(x)
        x = LeakyReLU(name=name + "_prelu")(x)
        return x

    return wrapper


def AttentionPooling(d_out):
    def wrapper(features):
        num_pts = features.shape[1]
        k_neighbors = features.shape[2]
        depth = features.shape[3]
        f_reshaped = Lambda(lambda x: tf.reshape(x, (-1, k_neighbors, depth)))(features)
        att_activation = Dense(depth, activation=None, use_bias=False)(f_reshaped)
        att_scores = Softmax()(att_activation)
        f_agg = Lambda(lambda x: tf.reduce_sum(Multiply()(x), axis=1))(
            [f_reshaped, att_scores]
        )
        f_agg = Lambda(lambda x: tf.reshape(x, (-1, num_pts, 1, depth)))(f_agg)
        f_agg = Conv2D(d_out, [1, 1])(f_agg)
        f_agg = LeakyReLU()(f_agg)
        return f_agg

    return wrapper


def RelativePosEncoding():
    def wrapper(xyz, neighbors_idx):
        n_xyz = GatherNeighbors(
            num_pts=neighbors_idx.shape[1], k_neighbors=neighbors_idx.shape[2]
        )(xyz, neighbors_idx)
        xyz_tile = Lambda(
            lambda x: tf.tile(
                tf.expand_dims(x, axis=2), (1, 1, tf.shape(neighbors_idx)[-1], 1)
            )
        )(xyz)
        relative_xyz = Subtract()([xyz_tile, n_xyz])
        relative_dist = Lambda(
            lambda x: tf.sqrt(tf.reduce_sum(tf.square(x), axis=-1, keepdims=True))
        )(relative_xyz)
        relative_feature = Concatenate(axis=-1)(
            [relative_dist, relative_xyz, xyz_tile, n_xyz]
        )
        return relative_feature
        # return relative_xyz

    return wrapper


def GatherIndices():
    def wrapper(input_tensor, indices):
        res = Lambda(lambda x: tf.compat.v1.batch_gather(x, indices))(input_tensor)
        return res

    return wrapper


def GatherNeighbors(num_pts=1000, k_neighbors=16):
    def wrapper(input_tensor, indices):
        indices_linear = Lambda(lambda x: tf.reshape(x, (-1, num_pts * k_neighbors)))(
            indices
        )
        res = Lambda(lambda x: tf.compat.v1.batch_gather(x, indices_linear))(
            input_tensor
        )
        return Lambda(
            lambda x: tf.reshape(
                x, (-1, num_pts, k_neighbors, input_tensor.get_shape()[-1])
            )
        )(res)

    return wrapper


def get_input_dimensions_and_offsets(settings: Settings):
    offsets = [0]
    num_elements = [settings.network.max_num_points]
    for level in range(settings.network.levels):
        offsets.append(int(offsets[-1] + settings.network.max_num_points / (4**level)))
        num_elements.append(int(settings.network.max_num_points / (4 ** (level + 1))))
    return offsets[-1], offsets, num_elements


def Network(settings: Settings, n_neurons=64, _n_neurons_fc=32):
    k_neighbors = settings.network.k_neighbors
    levels = settings.network.levels
    input_num_elements, offsets, num_elements = get_input_dimensions_and_offsets(
        settings
    )

    # Gather inputs
    input_dimension = np.array((input_num_elements, 3 + k_neighbors + 2)).astype(
        np.int_
    )
    _input = Input(
        shape=input_dimension,
        batch_size=settings.network.batch_size,
    )

    xyz_list, knn_list, ds_list, us_list = [], [], [], []
    for level in range(levels):
        xyz_list.append(
            Lambda(lambda array: array[:, offsets[level] : offsets[level + 1], :3])(
                _input
            )
        )
        knn_list.append(
            Lambda(
                lambda array: K.cast(
                    array[:, offsets[level] : offsets[level + 1], 3 : 3 + k_neighbors],
                    "int32",
                )
            )(_input)
        )
        ds_list.append(
            Lambda(
                lambda array: K.cast(
                    array[
                        :,
                        offsets[level] : offsets[level] + num_elements[level + 1],
                        3 + k_neighbors,
                    ],
                    "int32",
                )
            )(_input)
        )
        us_list.append(
            Lambda(
                lambda array: K.cast(
                    array[:, offsets[level] : offsets[level + 1], 3 + k_neighbors + 1],
                    "int32",
                )
            )(_input)
        )

    # Network
    x_stages = []
    x0_rel = RelativePosEncoding()(xyz_list[0], knn_list[0])
    x0 = Conv2DPreluBN(64, kernel_size=(1, 1), name="conv1x1_x0_01")(x0_rel)
    x0 = Conv2DPreluBN(64, kernel_size=(1, 1), name="conv1x1_x0_02")(x0)
    x0 = MaxPooling2D((1, k_neighbors), (1, k_neighbors))(x0)
    x0 = Conv2DPreluBN(
        64, kernel_size=(1, 1), batch_normalization=True, name="conv1x1_x0_03"
    )(x0)
    x_stages.append(x0)

    for level in range(1, settings.network.levels):
        depth = n_neurons * (2**level)
        name = f"stage{level:02d}"
        x = GatherIndices()(x_stages[level - 1], ds_list[level - 1])
        x_rel = RelativePosEncoding()(xyz_list[level], knn_list[level])
        x = GatherNeighbors(num_elements[level], k_neighbors=k_neighbors)(
            x, knn_list[level]
        )
        x = Concatenate(axis=-1)([x_rel, x])
        x = Conv2DPreluBN(depth, kernel_size=(1, 1), name=name + "conv1x1_01")(x)
        x = Conv2DPreluBN(depth, kernel_size=(1, 1), name=name + "conv1x1_02")(x)
        x = MaxPooling2D((1, k_neighbors), (1, k_neighbors))(x)
        x = Conv2DPreluBN(
            depth,
            kernel_size=(1, 1),
            batch_normalization=True,
            name=name + "conv1x1_03",
        )(x)
        x_stages.append(x)

    x_stages_up = [
        Conv2DPreluBN(
            n_neurons * (2 ** (settings.network.levels - 1)),
            kernel_size=(1, 1),
            batch_normalization=True,
            name="up_stage04_conv1x1up_01",
        )(x_stages[-1])
    ]

    for level in range(settings.network.levels - 2, -1, -1):
        depth = n_neurons * (2**level)
        name = f"up_stage{level:02d}"
        x_up = GatherIndices()(x_stages_up[-1], us_list[level])
        x_up = Concatenate(axis=-1)([x_stages[level], x_up])
        x_up = Conv2DPreluBN(depth, kernel_size=(1, 1), name=name + "conv1x1_01")(x_up)
        x_up = Conv2DPreluBN(depth // 2, kernel_size=(1, 1), name=name + "conv1x1_02")(
            x_up
        )
        x_stages_up.append(x_up)

    x = Conv2DPreluBN(
        settings.data.n_classes,
        kernel_size=(1, 1),
        batch_normalization=True,
        name="conv1x1_final",
    )(x_stages_up[-1])
    x = Dropout(0.1)(x)
    x = Softmax()(x)
    x = Lambda(lambda tensor: tf.squeeze(tensor, axis=2))(x)

    model = models.Model(_input, x)

    return model
